INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06070', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '南方有鳥焉，名曰蒙鳩，以羽為巢，而編之以髮，繫之葦苕，風至苕折，卵破子死。 巢非不完也，所繫者然也。西方有木焉，名曰射干，莖長四寸，生於高山之上， 而臨百仞之淵，木莖非能長也，所立者然也。（《荀子．勸學》）這段文字所表達 的寓意是：', '["天地間的生物各有天命，各安其時，人也當體會並順行天命", "環境對人的成長與學習影響很大，因此必須慎選所處的環境", "人必須懂得自省並從錯誤中學習，才能確保後代子孫的平安", "當人處在條件惡劣的情況下，解決之道就是自我改變求適應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06071', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「人情莫不欲處前，故惡人之自伐。自伐，皆欲勝之類也。是故自伐其善，則莫不 惡也。是所謂自伐歷之，則惡也。人情皆欲求勝，故悅人之謙。謙所以下之，下有 推與之意。是故人無賢愚，接之以謙，則無不色懌。是所謂以謙下之，則悅也。」 根據本文，下列選項敘述何者契合其為文之旨：', '["善於表現自我容易被人肯定", "懂得自謙往往容易被人喜歡", "不論賢愚，努力求勝即可成功", "分辨善惡，足以導正世俗人情 請依下文回答第19題至第20題： 帝城春欲暮，喧喧車馬度。共道牡丹時，相隨買花去。貴賤無常價，酬直看花數。 灼灼百朵紅，戔戔五束素。上張幄幕庇，旁織笆籬護。水洒復泥封，移來色如故。 家家習為俗，人人迷不悟。有一田舍翁，偶來買花處。低頭獨長歎，此歎無人諭。 一叢深色花，十戶中人賦。（《買花》）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06072', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '關於此詩的說明，何者錯誤？', '["此詩藉敘寫買花風尚凸顯出京城豪貴的奢華生活", "「田舍翁」係為賣花而來，因而發出花賤傷農之嘆", "「灼灼百朵紅，戔戔五束素」寫牡丹花之價格昂貴", "「上張幄幕庇，旁織笆籬護」寫牡丹備受呵護的情形"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06073', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '此詩的旨趣是：', '["針砭時事，反映社會現實", "歌詠牡丹，抒發生活情趣", "以物擬人，感嘆青春易逝", "藉古諷今，批判流俗澆薄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06074', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '「社會工作」作為人類服務的專業之一，有其固有的價值體系而須時時提醒社會工
作專業人員遵行。請說明社會工作的價值包含那幾項？並申論社會工作專業人員應
具備何種基本態度？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06075', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '若塵爆事件引發大量傷患湧入醫院，你是一位醫務社會工作人員，請申論如何運用
危機調適模式協助醫院處理受到塵爆傷害的案主與家屬？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06076', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會工作本質與特性描述，下列何者錯誤？ 每個人都有義務去尋找自我成就的方法，即便是最弱勢的受助者，也應該努力去實現 社會工作非常強調家庭在塑造及影響個人行為的重要性，因此維繫家庭完整性的原則高於一切 傳統的社會工作服務強調治療與解決問題為本，近年來則越發重視預防與充權導向 社會工作過程主要呈現在與個案之關係建立，現代社會工作應學習如何以電腦和網絡互連技術，進入 虛擬社會', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06077', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不屬於臺灣當前學校社會工作之服務內涵？ 新移民子女的課業輔導   中輟生輔導 家庭暴力目睹兒童輔導   社區中途關懷站', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06078', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作實務越來越變成與數字相關，管理人員致力於標準化與操作化一種「個案進來—將其分類—送 走個案」的流程。下列那一個概念，最符合此一敘述的觀點？ 需求導向服務  個案中心模式  新管理主義  服務整合', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06079', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者應以全人關懷的價值觀，確保服務對象獲得社會所提供的保護和機會，和諧地使用其能力， 滿足各種需求。下列何者不屬於社會工作者所需關注的全人需求？ 靈性需求  比較需求  生理需求  美學需求', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b55fd4e38fe3", "answer_pdf_sha1": "e024a7c44cc7", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
